import React, { useContext, useState } from 'react';
import MagicBellContext from '@magicbell/react/internal/context/magicbell.context';

function CustomNotificationItem({ data, index, onNotificationClick }) {
  const ctx = useContext(MagicBellContext);
  const [isRead, setIsRead] = useState(() => Boolean(data.readAt));

  const isUnread = !isRead;

  function handleMarkRead(e) {
    e.stopPropagation();
    ctx.notifications.markAsRead(data.id);
    setIsRead(true);
  }

  return (
    <div className="custom-notification-item">
      <div className="custom-notification-title">{data.title}</div>
      {data.content && (
        <div className="custom-notification-content">{data.content}</div>
      )}
      {isUnread && (
        <button
          className="custom-mark-read-btn"
          onClick={handleMarkRead}
          type="button"
        >
          Mark as read
        </button>
      )}
    </div>
  );
}

export default CustomNotificationItem;

import React, { useState, useEffect } from 'react';
import { MagicBellProvider, FloatingInbox, Inbox } from '@magicbell/react';
import CustomNotificationItem from './CustomNotificationItem';

function CustomInbox(props) {
  return <Inbox {...props} ItemComponent={CustomNotificationItem} />;
}

function App() {
  const [token, setToken] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('/token')
      .then((res) => res.json())
      .then((data) => setToken(data.token))
      .catch((err) => setError(err.message));
  }, []);

  if (error) {
    return <div>Error loading token: {error}</div>;
  }

  if (!token) {
    return <div>Loading...</div>;
  }

  return (
    <div className="App">
      <MagicBellProvider token={token}>
        <FloatingInbox InboxComponent={CustomInbox} />
      </MagicBellProvider>
    </div>
  );
}

export default App;

