import React, { useState, useCallback } from 'react';

const MAGICBELL_API_BASE = 'https://api.magicbell.com/v2';

// Token will be injected via context
export const TokenContext = React.createContext(null);

function CustomNotificationItem({ data, index, onNotificationClick }) {
  const token = React.useContext(TokenContext);
  const [isRead, setIsRead] = useState(() => Boolean(data.readAt));

  const handleMarkRead = useCallback(
    async (e) => {
      e.stopPropagation();
      try {
        await fetch(`${MAGICBELL_API_BASE}/notifications/${data.id}/read`, {
          method: 'POST',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        });
        setIsRead(true);
      } catch (err) {
        console.error('Failed to mark notification as read:', err);
      }
    },
    [data.id, token]
  );

  return (
    <div className="custom-notification-item">
      <div className="custom-notification-title">{data.title}</div>
      {data.content && (
        <div className="custom-notification-content">{data.content}</div>
      )}
      {!isRead && (
        <button
          className="custom-mark-read-btn"
          onClick={handleMarkRead}
          type="button"
        >
          Mark as read
        </button>
      )}
    </div>
  );
}

export default CustomNotificationItem;

import React, { useState, useEffect } from 'react';
import { MagicBellProvider, FloatingInbox, Inbox } from '@magicbell/react';
import CustomNotificationItem, { TokenContext } from './CustomNotificationItem';

function CustomInbox(props) {
  return <Inbox {...props} ItemComponent={CustomNotificationItem} />;
}

function App() {
  const [token, setToken] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('/token')
      .then((res) => res.json())
      .then((data) => setToken(data.token))
      .catch((err) => setError(err.message));
  }, []);

  if (error) {
    return <div>Error loading token: {error}</div>;
  }

  if (!token) {
    return <div>Loading...</div>;
  }

  return (
    <div className="App">
      <TokenContext.Provider value={token}>
        <MagicBellProvider token={token}>
          <FloatingInbox InboxComponent={CustomInbox} />
        </MagicBellProvider>
      </TokenContext.Provider>
    </div>
  );
}

export default App;

